-- Web Empire 800 Tools Program — Production Wave 3
-- Adds 100 deterministic formula tools across 10 new categories.
-- Safe, idempotent upserts. No destructive deletes.

begin;

insert into public.categories(
  slug, name_ar, name_en, description, icon, style_key, sort_order, is_active
)
values
  ('automotive-tools', 'أدوات السيارات', 'Automotive Tools', 'حاسبات الوقود والملكية والصيانة والتشغيل.', 'car', 'violet', 300, true),
  ('construction-tools', 'أدوات البناء', 'Construction Tools', 'حاسبات المواد والكميات والتكاليف في مشاريع البناء.', 'hard-hat', 'gold', 310, true),
  ('agriculture-tools', 'أدوات الزراعة', 'Agriculture Tools', 'حاسبات المحاصيل والري والتسميد والإنتاج الزراعي.', 'sprout', 'green', 320, true),
  ('event-tools', 'أدوات الفعاليات', 'Event Tools', 'حاسبات التذاكر والحضور والرعاية والتشغيل.', 'calendar-days', 'cyan', 330, true),
  ('hr-tools', 'أدوات الموارد البشرية', 'HR Tools', 'حاسبات التوظيف والاحتفاظ والغياب وتكلفة الموظفين.', 'users', 'violet', 340, true),
  ('seo-tools', 'أدوات تحسين محركات البحث', 'SEO Tools', 'حاسبات الظهور والنقر والتحويل والنمو العضوي.', 'search', 'gold', 350, true),
  ('web-tools', 'أدوات الويب', 'Web Tools', 'حاسبات الأداء والبيانات والخوادم والتحويل الرقمي.', 'globe', 'cyan', 360, true),
  ('design-tools', 'أدوات التصميم', 'Design Tools', 'حاسبات التسعير والطباعة والأبعاد والإنتاج التصميمي.', 'palette', 'violet', 370, true),
  ('customer-service-tools', 'أدوات خدمة العملاء', 'Customer Service Tools', 'حاسبات التذاكر والجودة والاستجابة ومستوى الخدمة.', 'headphones', 'gold', 380, true),
  ('personal-finance-tools', 'أدوات المالية الشخصية', 'Personal Finance Tools', 'حاسبات الادخار والديون والتدفق النقدي والميزانية.', 'wallet-cards', 'green', 390, true)
on conflict (slug) do update set
  name_ar = excluded.name_ar,
  name_en = excluded.name_en,
  description = excluded.description,
  icon = excluded.icon,
  style_key = excluded.style_key,
  sort_order = excluded.sort_order,
  is_active = true;

insert into public.category_translations(category_id, locale_id, name, description)
select category.id, locale.id, seed.name, seed.description
from (
  values
    ('automotive-tools', 'ar', 'أدوات السيارات', 'حاسبات الوقود والملكية والصيانة والتشغيل.'),
    ('automotive-tools', 'en', 'Automotive Tools', 'حاسبات الوقود والملكية والصيانة والتشغيل.'),
    ('construction-tools', 'ar', 'أدوات البناء', 'حاسبات المواد والكميات والتكاليف في مشاريع البناء.'),
    ('construction-tools', 'en', 'Construction Tools', 'حاسبات المواد والكميات والتكاليف في مشاريع البناء.'),
    ('agriculture-tools', 'ar', 'أدوات الزراعة', 'حاسبات المحاصيل والري والتسميد والإنتاج الزراعي.'),
    ('agriculture-tools', 'en', 'Agriculture Tools', 'حاسبات المحاصيل والري والتسميد والإنتاج الزراعي.'),
    ('event-tools', 'ar', 'أدوات الفعاليات', 'حاسبات التذاكر والحضور والرعاية والتشغيل.'),
    ('event-tools', 'en', 'Event Tools', 'حاسبات التذاكر والحضور والرعاية والتشغيل.'),
    ('hr-tools', 'ar', 'أدوات الموارد البشرية', 'حاسبات التوظيف والاحتفاظ والغياب وتكلفة الموظفين.'),
    ('hr-tools', 'en', 'HR Tools', 'حاسبات التوظيف والاحتفاظ والغياب وتكلفة الموظفين.'),
    ('seo-tools', 'ar', 'أدوات تحسين محركات البحث', 'حاسبات الظهور والنقر والتحويل والنمو العضوي.'),
    ('seo-tools', 'en', 'SEO Tools', 'حاسبات الظهور والنقر والتحويل والنمو العضوي.'),
    ('web-tools', 'ar', 'أدوات الويب', 'حاسبات الأداء والبيانات والخوادم والتحويل الرقمي.'),
    ('web-tools', 'en', 'Web Tools', 'حاسبات الأداء والبيانات والخوادم والتحويل الرقمي.'),
    ('design-tools', 'ar', 'أدوات التصميم', 'حاسبات التسعير والطباعة والأبعاد والإنتاج التصميمي.'),
    ('design-tools', 'en', 'Design Tools', 'حاسبات التسعير والطباعة والأبعاد والإنتاج التصميمي.'),
    ('customer-service-tools', 'ar', 'أدوات خدمة العملاء', 'حاسبات التذاكر والجودة والاستجابة ومستوى الخدمة.'),
    ('customer-service-tools', 'en', 'Customer Service Tools', 'حاسبات التذاكر والجودة والاستجابة ومستوى الخدمة.'),
    ('personal-finance-tools', 'ar', 'أدوات المالية الشخصية', 'حاسبات الادخار والديون والتدفق النقدي والميزانية.'),
    ('personal-finance-tools', 'en', 'Personal Finance Tools', 'حاسبات الادخار والديون والتدفق النقدي والميزانية.')
) as seed(category_slug, locale_code, name, description)
join public.categories category on category.slug = seed.category_slug
join public.locales locale on locale.code = seed.locale_code
on conflict (category_id, locale_id) do update set
  name = excluded.name,
  description = excluded.description,
  updated_at = now();

create temporary table wave3_formula_tool_seed (
  category_slug text not null,
  slug text not null,
  title_ar text not null,
  title_en text not null,
  description_ar text not null,
  description_en text not null,
  runtime_config jsonb not null,
  input_fields jsonb not null,
  english_fields jsonb not null,
  submit_ar text not null,
  submit_en text not null,
  sort_order integer not null,
  is_featured boolean not null
) on commit drop;

insert into wave3_formula_tool_seed(
  category_slug, slug, title_ar, title_en, description_ar, description_en,
  runtime_config, input_fields, english_fields, submit_ar, submit_en,
  sort_order, is_featured
)
values
  ('automotive-tools', 'vehicle-fuel-cost-calculator', 'حاسبة تكلفة وقود السيارة', 'Vehicle Fuel Cost Calculator', 'احسب تكلفة الوقود لمسافة محددة.', 'Calculate fuel cost for a given distance.', '{"expression":"distance / km_per_liter * fuel_price","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"تكلفة الوقود","resultLabelEn":"Fuel cost","decimals":2,"showEquation":true}'::jsonb, '[{"key":"distance","label":"المسافة بالكيلومتر","type":"number","required":true,"step":0.01,"min":0},{"key":"km_per_liter","label":"كفاءة السيارة كم/لتر","type":"number","required":true,"step":0.01,"min":0.01},{"key":"fuel_price","label":"سعر اللتر","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"distance","label":"Distance in km","type":"number","required":true,"step":0.01,"min":0},{"key":"km_per_liter","label":"Vehicle efficiency km/l","type":"number","required":true,"step":0.01,"min":0.01},{"key":"fuel_price","label":"Fuel price per liter","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 3000, true),
  ('automotive-tools', 'annual-fuel-cost-calculator', 'حاسبة تكلفة الوقود السنوية', 'Annual Fuel Cost Calculator', 'قدّر تكلفة الوقود السنوية.', 'Estimate annual fuel cost.', '{"expression":"monthly_distance * 12 / km_per_liter * fuel_price","outputUnitAr":" ر.س/سنة","outputUnitEn":" SAR/year","resultLabelAr":"تكلفة الوقود السنوية","resultLabelEn":"Annual fuel cost","decimals":2,"showEquation":true}'::jsonb, '[{"key":"monthly_distance","label":"المسافة الشهرية","type":"number","required":true,"step":0.01,"min":0},{"key":"km_per_liter","label":"كفاءة السيارة كم/لتر","type":"number","required":true,"step":0.01,"min":0.01},{"key":"fuel_price","label":"سعر اللتر","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"monthly_distance","label":"Monthly distance","type":"number","required":true,"step":0.01,"min":0},{"key":"km_per_liter","label":"Vehicle efficiency km/l","type":"number","required":true,"step":0.01,"min":0.01},{"key":"fuel_price","label":"Fuel price per liter","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 3001, false),
  ('automotive-tools', 'vehicle-depreciation-calculator', 'حاسبة انخفاض قيمة السيارة', 'Vehicle Depreciation Calculator', 'قدّر قيمة السيارة بعد معدل انخفاض سنوي.', 'Estimate vehicle value after annual depreciation.', '{"expression":"purchase_price * ((1 - annual_rate / 100) ^ years)","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"القيمة التقديرية الحالية","resultLabelEn":"Estimated current value","decimals":2,"showEquation":true}'::jsonb, '[{"key":"purchase_price","label":"سعر الشراء","type":"number","required":true,"step":0.01,"min":0},{"key":"annual_rate","label":"معدل الانخفاض السنوي","type":"number","required":true,"step":0.01,"min":0,"max":100},{"key":"years","label":"عدد السنوات","type":"number","required":true,"step":1,"min":0}]'::jsonb, '[{"key":"purchase_price","label":"Purchase price","type":"number","required":true,"step":0.01,"min":0},{"key":"annual_rate","label":"Annual depreciation rate","type":"number","required":true,"step":0.01,"min":0,"max":100},{"key":"years","label":"Years","type":"number","required":true,"step":1,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 3002, false),
  ('automotive-tools', 'vehicle-maintenance-budget-calculator', 'حاسبة ميزانية صيانة السيارة', 'Vehicle Maintenance Budget Calculator', 'احسب ميزانية الصيانة السنوية من متوسط الصيانة الشهرية.', 'Calculate annual maintenance budget from monthly average.', '{"expression":"monthly_maintenance * 12","outputUnitAr":" ر.س/سنة","outputUnitEn":" SAR/year","resultLabelAr":"ميزانية الصيانة السنوية","resultLabelEn":"Annual maintenance budget","decimals":2,"showEquation":true}'::jsonb, '[{"key":"monthly_maintenance","label":"متوسط الصيانة الشهرية","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"monthly_maintenance","label":"Average monthly maintenance","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 3003, false),
  ('automotive-tools', 'vehicle-ownership-monthly-cost-calculator', 'حاسبة تكلفة امتلاك السيارة شهريًا', 'Monthly Vehicle Ownership Cost Calculator', 'اجمع التمويل والتأمين والوقود والصيانة شهريًا.', 'Combine financing, insurance, fuel, and maintenance costs.', '{"expression":"finance_payment + insurance_monthly + fuel_monthly + maintenance_monthly","outputUnitAr":" ر.س/شهر","outputUnitEn":" SAR/month","resultLabelAr":"تكلفة الملكية الشهرية","resultLabelEn":"Monthly ownership cost","decimals":2,"showEquation":true}'::jsonb, '[{"key":"finance_payment","label":"القسط الشهري","type":"number","required":true,"step":0.01,"min":0},{"key":"insurance_monthly","label":"التأمين الشهري","type":"number","required":true,"step":0.01,"min":0},{"key":"fuel_monthly","label":"الوقود الشهري","type":"number","required":true,"step":0.01,"min":0},{"key":"maintenance_monthly","label":"الصيانة الشهرية","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"finance_payment","label":"Monthly finance payment","type":"number","required":true,"step":0.01,"min":0},{"key":"insurance_monthly","label":"Monthly insurance","type":"number","required":true,"step":0.01,"min":0},{"key":"fuel_monthly","label":"Monthly fuel","type":"number","required":true,"step":0.01,"min":0},{"key":"maintenance_monthly","label":"Monthly maintenance","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 3004, true),
  ('automotive-tools', 'tire-cost-per-km-calculator', 'حاسبة تكلفة الإطارات لكل كيلومتر', 'Tire Cost per Kilometer Calculator', 'احسب تكلفة الإطارات لكل كيلومتر.', 'Calculate tire cost per kilometer.', '{"expression":"tire_set_cost / tire_lifespan_km","outputUnitAr":" ر.س/كم","outputUnitEn":" SAR/km","resultLabelAr":"تكلفة الإطارات لكل كيلومتر","resultLabelEn":"Tire cost per km","decimals":4,"showEquation":true}'::jsonb, '[{"key":"tire_set_cost","label":"تكلفة طقم الإطارات","type":"number","required":true,"step":0.01,"min":0},{"key":"tire_lifespan_km","label":"العمر بالكيلومتر","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"tire_set_cost","label":"Tire set cost","type":"number","required":true,"step":0.01,"min":0},{"key":"tire_lifespan_km","label":"Tire lifespan in km","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 3005, false),
  ('automotive-tools', 'lease-mileage-overage-calculator', 'حاسبة تجاوز مسافة التأجير', 'Lease Mileage Overage Calculator', 'احسب رسوم تجاوز المسافة المسموحة.', 'Calculate lease mileage overage charges.', '{"expression":"extra_km * fee_per_km","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"رسوم التجاوز","resultLabelEn":"Overage fee","decimals":2,"showEquation":true}'::jsonb, '[{"key":"extra_km","label":"الكيلومترات الزائدة","type":"number","required":true,"step":0.01,"min":0},{"key":"fee_per_km","label":"الرسوم لكل كيلومتر","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"extra_km","label":"Extra kilometers","type":"number","required":true,"step":0.01,"min":0},{"key":"fee_per_km","label":"Fee per kilometer","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 3006, false),
  ('automotive-tools', 'vehicle-finance-total-cost-calculator', 'حاسبة إجمالي تكلفة تمويل السيارة', 'Vehicle Finance Total Cost Calculator', 'احسب إجمالي الدفعات على مدة التمويل.', 'Calculate total finance payments over the term.', '{"expression":"monthly_payment * months + down_payment","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"إجمالي تكلفة التمويل","resultLabelEn":"Total finance cost","decimals":2,"showEquation":true}'::jsonb, '[{"key":"monthly_payment","label":"القسط الشهري","type":"number","required":true,"step":0.01,"min":0},{"key":"months","label":"عدد الأشهر","type":"number","required":true,"step":1,"min":1},{"key":"down_payment","label":"الدفعة الأولى","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"monthly_payment","label":"Monthly payment","type":"number","required":true,"step":0.01,"min":0},{"key":"months","label":"Months","type":"number","required":true,"step":1,"min":1},{"key":"down_payment","label":"Down payment","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 3007, false),
  ('automotive-tools', 'ride-profit-calculator', 'حاسبة ربح الرحلة', 'Ride Profit Calculator', 'احسب ربح الرحلة بعد الوقود والمصروفات.', 'Calculate trip profit after fuel and expenses.', '{"expression":"ride_revenue - fuel_cost - other_costs","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"ربح الرحلة","resultLabelEn":"Ride profit","decimals":2,"showEquation":true}'::jsonb, '[{"key":"ride_revenue","label":"إيراد الرحلة","type":"number","required":true,"step":0.01,"min":0},{"key":"fuel_cost","label":"تكلفة الوقود","type":"number","required":true,"step":0.01,"min":0},{"key":"other_costs","label":"مصروفات أخرى","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"ride_revenue","label":"Ride revenue","type":"number","required":true,"step":0.01,"min":0},{"key":"fuel_cost","label":"Fuel cost","type":"number","required":true,"step":0.01,"min":0},{"key":"other_costs","label":"Other costs","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 3008, false),
  ('automotive-tools', 'vehicle-cost-per-km-calculator', 'حاسبة تكلفة السيارة لكل كيلومتر', 'Vehicle Cost per Kilometer Calculator', 'احسب التكلفة التشغيلية لكل كيلومتر.', 'Calculate operating cost per kilometer.', '{"expression":"annual_cost / annual_km","outputUnitAr":" ر.س/كم","outputUnitEn":" SAR/km","resultLabelAr":"التكلفة لكل كيلومتر","resultLabelEn":"Cost per kilometer","decimals":4,"showEquation":true}'::jsonb, '[{"key":"annual_cost","label":"إجمالي التكلفة السنوية","type":"number","required":true,"step":0.01,"min":0},{"key":"annual_km","label":"الكيلومترات السنوية","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"annual_cost","label":"Total annual cost","type":"number","required":true,"step":0.01,"min":0},{"key":"annual_km","label":"Annual kilometers","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 3009, false),
  ('construction-tools', 'concrete-volume-calculator', 'حاسبة حجم الخرسانة', 'Concrete Volume Calculator', 'احسب حجم الخرسانة للمساحة المستطيلة.', 'Calculate concrete volume for a rectangular area.', '{"expression":"length * width * depth","outputUnitAr":" م³","outputUnitEn":" m³","resultLabelAr":"حجم الخرسانة","resultLabelEn":"Concrete volume","decimals":2,"showEquation":true}'::jsonb, '[{"key":"length","label":"الطول بالمتر","type":"number","required":true,"step":0.01,"min":0},{"key":"width","label":"العرض بالمتر","type":"number","required":true,"step":0.01,"min":0},{"key":"depth","label":"السماكة بالمتر","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"length","label":"Length in meters","type":"number","required":true,"step":0.01,"min":0},{"key":"width","label":"Width in meters","type":"number","required":true,"step":0.01,"min":0},{"key":"depth","label":"Depth in meters","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 3010, true),
  ('construction-tools', 'brick-count-calculator', 'حاسبة عدد الطوب', 'Brick Count Calculator', 'قدّر عدد الطوب المطلوب لمساحة جدار.', 'Estimate bricks needed for a wall area.', '{"expression":"wall_area / brick_area * (1 + waste_rate / 100)","outputUnitAr":" طوبة","outputUnitEn":" bricks","resultLabelAr":"عدد الطوب التقديري","resultLabelEn":"Estimated brick count","decimals":0,"showEquation":true}'::jsonb, '[{"key":"wall_area","label":"مساحة الجدار م²","type":"number","required":true,"step":0.01,"min":0},{"key":"brick_area","label":"مساحة وجه الطوبة م²","type":"number","required":true,"step":0.01,"min":1e-06},{"key":"waste_rate","label":"نسبة الهدر","type":"number","required":true,"step":0.01,"min":0,"max":100,"defaultValue":5}]'::jsonb, '[{"key":"wall_area","label":"Wall area m²","type":"number","required":true,"step":0.01,"min":0},{"key":"brick_area","label":"Brick face area m²","type":"number","required":true,"step":0.01,"min":1e-06},{"key":"waste_rate","label":"Waste rate","type":"number","required":true,"step":0.01,"min":0,"max":100,"defaultValue":5}]'::jsonb, 'احسب النتيجة', 'Calculate', 3011, false),
  ('construction-tools', 'paint-liters-calculator', 'حاسبة كمية الدهان', 'Paint Quantity Calculator', 'قدّر لترات الدهان لمساحة وعدد طبقات.', 'Estimate paint liters for area and coats.', '{"expression":"area * coats / coverage_per_liter","outputUnitAr":" لتر","outputUnitEn":" liters","resultLabelAr":"كمية الدهان","resultLabelEn":"Paint quantity","decimals":2,"showEquation":true}'::jsonb, '[{"key":"area","label":"المساحة م²","type":"number","required":true,"step":0.01,"min":0},{"key":"coats","label":"عدد الطبقات","type":"number","required":true,"step":1,"min":1},{"key":"coverage_per_liter","label":"التغطية لكل لتر م²","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"area","label":"Area m²","type":"number","required":true,"step":0.01,"min":0},{"key":"coats","label":"Number of coats","type":"number","required":true,"step":1,"min":1},{"key":"coverage_per_liter","label":"Coverage per liter m²","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 3012, true),
  ('construction-tools', 'tile-quantity-calculator', 'حاسبة كمية البلاط', 'Tile Quantity Calculator', 'احسب عدد البلاط المطلوب مع الهدر.', 'Calculate required tiles including waste.', '{"expression":"floor_area / tile_area * (1 + waste_rate / 100)","outputUnitAr":" بلاطة","outputUnitEn":" tiles","resultLabelAr":"عدد البلاط","resultLabelEn":"Tile count","decimals":0,"showEquation":true}'::jsonb, '[{"key":"floor_area","label":"مساحة الأرضية م²","type":"number","required":true,"step":0.01,"min":0},{"key":"tile_area","label":"مساحة البلاطة م²","type":"number","required":true,"step":0.01,"min":1e-06},{"key":"waste_rate","label":"نسبة الهدر","type":"number","required":true,"step":0.01,"min":0,"max":100,"defaultValue":10}]'::jsonb, '[{"key":"floor_area","label":"Floor area m²","type":"number","required":true,"step":0.01,"min":0},{"key":"tile_area","label":"Tile area m²","type":"number","required":true,"step":0.01,"min":1e-06},{"key":"waste_rate","label":"Waste rate","type":"number","required":true,"step":0.01,"min":0,"max":100,"defaultValue":10}]'::jsonb, 'احسب النتيجة', 'Calculate', 3013, false),
  ('construction-tools', 'cement-bags-calculator', 'حاسبة أكياس الأسمنت', 'Cement Bags Calculator', 'قدّر عدد أكياس الأسمنت من الوزن المطلوب.', 'Estimate cement bags from required weight.', '{"expression":"cement_weight / bag_weight","outputUnitAr":" كيس","outputUnitEn":" bags","resultLabelAr":"عدد الأكياس","resultLabelEn":"Bag count","decimals":1,"showEquation":true}'::jsonb, '[{"key":"cement_weight","label":"وزن الأسمنت المطلوب كجم","type":"number","required":true,"step":0.01,"min":0},{"key":"bag_weight","label":"وزن الكيس كجم","type":"number","required":true,"step":0.01,"min":0.01,"defaultValue":50}]'::jsonb, '[{"key":"cement_weight","label":"Required cement weight kg","type":"number","required":true,"step":0.01,"min":0},{"key":"bag_weight","label":"Bag weight kg","type":"number","required":true,"step":0.01,"min":0.01,"defaultValue":50}]'::jsonb, 'احسب النتيجة', 'Calculate', 3014, false),
  ('construction-tools', 'wall-area-calculator', 'حاسبة مساحة الجدار', 'Wall Area Calculator', 'احسب مساحة الجدار بعد خصم الفتحات.', 'Calculate wall area after subtracting openings.', '{"expression":"wall_length * wall_height - openings_area","outputUnitAr":" م²","outputUnitEn":" m²","resultLabelAr":"مساحة الجدار الصافية","resultLabelEn":"Net wall area","decimals":2,"showEquation":true}'::jsonb, '[{"key":"wall_length","label":"طول الجدار","type":"number","required":true,"step":0.01,"min":0},{"key":"wall_height","label":"ارتفاع الجدار","type":"number","required":true,"step":0.01,"min":0},{"key":"openings_area","label":"مساحة الأبواب والنوافذ","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"wall_length","label":"Wall length","type":"number","required":true,"step":0.01,"min":0},{"key":"wall_height","label":"Wall height","type":"number","required":true,"step":0.01,"min":0},{"key":"openings_area","label":"Openings area","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 3015, false),
