  ('design-tools', 'print-run-cost-calculator', 'حاسبة تكلفة كمية الطباعة', 'Print Run Cost Calculator', 'احسب تكلفة الطباعة من الكمية وسعر الوحدة.', 'Calculate print run cost.', '{"expression":"quantity * cost_per_unit + setup_cost","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"إجمالي تكلفة الطباعة","resultLabelEn":"Total print cost","decimals":2,"showEquation":true}'::jsonb, '[{"key":"quantity","label":"الكمية","type":"number","required":true,"step":1,"min":0},{"key":"cost_per_unit","label":"تكلفة الوحدة","type":"number","required":true,"step":0.01,"min":0},{"key":"setup_cost","label":"تكلفة التجهيز","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"quantity","label":"Quantity","type":"number","required":true,"step":1,"min":0},{"key":"cost_per_unit","label":"Cost per unit","type":"number","required":true,"step":0.01,"min":0},{"key":"setup_cost","label":"Setup cost","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 3079, false),
