  ('customer-service-tools', 'average-resolution-time-calculator', 'حاسبة متوسط زمن الحل', 'Average Resolution Time Calculator', 'احسب متوسط زمن حل التذاكر.', 'Calculate average ticket resolution time.', '{"expression":"total_resolution_hours / resolved_tickets","outputUnitAr":" ساعة","outputUnitEn":" hours","resultLabelAr":"متوسط زمن الحل","resultLabelEn":"Average resolution time","decimals":2,"showEquation":true}'::jsonb, '[{"key":"total_resolution_hours","label":"إجمالي ساعات الحل","type":"number","required":true,"step":0.01,"min":0},{"key":"resolved_tickets","label":"التذاكر المحلولة","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"total_resolution_hours","label":"Total resolution hours","type":"number","required":true,"step":0.01,"min":0},{"key":"resolved_tickets","label":"Resolved tickets","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 3081, true),
  ('customer-service-tools', 'csat-score-calculator', 'حاسبة رضا العملاء CSAT', 'CSAT Score Calculator', 'احسب نسبة التقييمات الإيجابية.', 'Calculate customer satisfaction score.', '{"expression":"positive_responses / total_responses * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"درجة رضا العملاء","resultLabelEn":"CSAT score","decimals":2,"showEquation":true}'::jsonb, '[{"key":"positive_responses","label":"التقييمات الإيجابية","type":"number","required":true,"step":1,"min":0},{"key":"total_responses","label":"إجمالي الردود","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"positive_responses","label":"Positive responses","type":"number","required":true,"step":1,"min":0},{"key":"total_responses","label":"Total responses","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 3082, false),
  ('customer-service-tools', 'nps-score-calculator', 'حاسبة صافي نقاط الترويج NPS', 'NPS Score Calculator', 'احسب NPS من المروجين والمنتقدين.', 'Calculate NPS from promoters and detractors.', '{"expression":"(promoters - detractors) / responses * 100","outputUnitAr":" نقطة","outputUnitEn":" points","resultLabelAr":"صافي نقاط الترويج","resultLabelEn":"NPS score","decimals":2,"showEquation":true}'::jsonb, '[{"key":"promoters","label":"المروجون","type":"number","required":true,"step":1,"min":0},{"key":"detractors","label":"المنتقدون","type":"number","required":true,"step":1,"min":0},{"key":"responses","label":"إجمالي الردود","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"promoters","label":"Promoters","type":"number","required":true,"step":1,"min":0},{"key":"detractors","label":"Detractors","type":"number","required":true,"step":1,"min":0},{"key":"responses","label":"Total responses","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 3083, false),
  ('customer-service-tools', 'ticket-backlog-calculator', 'حاسبة تراكم التذاكر', 'Ticket Backlog Calculator', 'احسب التذاكر المتبقية غير المحلولة.', 'Calculate remaining unresolved tickets.', '{"expression":"opened_tickets - resolved_tickets","outputUnitAr":" تذكرة","outputUnitEn":" tickets","resultLabelAr":"تراكم التذاكر","resultLabelEn":"Ticket backlog","decimals":0,"showEquation":true}'::jsonb, '[{"key":"opened_tickets","label":"التذاكر المفتوحة","type":"number","required":true,"step":1,"min":0},{"key":"resolved_tickets","label":"التذاكر المحلولة","type":"number","required":true,"step":1,"min":0}]'::jsonb, '[{"key":"opened_tickets","label":"Opened tickets","type":"number","required":true,"step":1,"min":0},{"key":"resolved_tickets","label":"Resolved tickets","type":"number","required":true,"step":1,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 3084, false),
  ('customer-service-tools', 'support-cost-per-ticket-calculator', 'حاسبة تكلفة الدعم لكل تذكرة', 'Support Cost per Ticket Calculator', 'احسب متوسط تكلفة دعم التذكرة.', 'Calculate average support cost per ticket.', '{"expression":"support_cost / tickets","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"التكلفة لكل تذكرة","resultLabelEn":"Cost per ticket","decimals":2,"showEquation":true}'::jsonb, '[{"key":"support_cost","label":"إجمالي تكلفة الدعم","type":"number","required":true,"step":0.01,"min":0},{"key":"tickets","label":"عدد التذاكر","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"support_cost","label":"Total support cost","type":"number","required":true,"step":0.01,"min":0},{"key":"tickets","label":"Tickets","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 3085, false),
