  ('customer-service-tools', 'escalation-rate-calculator', 'حاسبة معدل التصعيد', 'Escalation Rate Calculator', 'احسب نسبة التذاكر التي تم تصعيدها.', 'Calculate escalated tickets as a percentage.', '{"expression":"escalated_tickets / total_tickets * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"معدل التصعيد","resultLabelEn":"Escalation rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"escalated_tickets","label":"التذاكر المصعّدة","type":"number","required":true,"step":1,"min":0},{"key":"total_tickets","label":"إجمالي التذاكر","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"escalated_tickets","label":"Escalated tickets","type":"number","required":true,"step":1,"min":0},{"key":"total_tickets","label":"Total tickets","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 3088, false),
  ('customer-service-tools', 'support-agent-utilization-calculator', 'حاسبة استغلال موظف الدعم', 'Support Agent Utilization Calculator', 'احسب نسبة وقت العمل المنتج لموظف الدعم.', 'Calculate productive support time as a percentage.', '{"expression":"productive_hours / available_hours * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"معدل استغلال الموظف","resultLabelEn":"Agent utilization","decimals":2,"showEquation":true}'::jsonb, '[{"key":"productive_hours","label":"الساعات المنتجة","type":"number","required":true,"step":0.01,"min":0},{"key":"available_hours","label":"الساعات المتاحة","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"productive_hours","label":"Productive hours","type":"number","required":true,"step":0.01,"min":0},{"key":"available_hours","label":"Available hours","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 3089, false),
  ('personal-finance-tools', 'monthly-savings-rate-calculator', 'حاسبة معدل الادخار الشهري', 'Monthly Savings Rate Calculator', 'احسب نسبة الادخار من الدخل.', 'Calculate savings as a percentage of income.', '{"expression":"monthly_savings / monthly_income * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"معدل الادخار","resultLabelEn":"Savings rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"monthly_savings","label":"الادخار الشهري","type":"number","required":true,"step":0.01,"min":0},{"key":"monthly_income","label":"الدخل الشهري","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"monthly_savings","label":"Monthly savings","type":"number","required":true,"step":0.01,"min":0},{"key":"monthly_income","label":"Monthly income","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 3090, true),
  ('personal-finance-tools', 'emergency-fund-months-calculator', 'حاسبة أشهر صندوق الطوارئ', 'Emergency Fund Months Calculator', 'احسب عدد الأشهر التي يغطيها صندوق الطوارئ.', 'Calculate how many months an emergency fund covers.', '{"expression":"emergency_fund / monthly_expenses","outputUnitAr":" شهر","outputUnitEn":" months","resultLabelAr":"أشهر التغطية","resultLabelEn":"Months covered","decimals":2,"showEquation":true}'::jsonb, '[{"key":"emergency_fund","label":"قيمة صندوق الطوارئ","type":"number","required":true,"step":0.01,"min":0},{"key":"monthly_expenses","label":"المصروفات الشهرية","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"emergency_fund","label":"Emergency fund","type":"number","required":true,"step":0.01,"min":0},{"key":"monthly_expenses","label":"Monthly expenses","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 3091, true),
  ('personal-finance-tools', 'debt-to-income-ratio-calculator', 'حاسبة نسبة الدين إلى الدخل', 'Debt-to-Income Ratio Calculator', 'احسب نسبة الأقساط إلى الدخل الشهري.', 'Calculate debt payments as a percentage of monthly income.', '{"expression":"monthly_debt_payments / monthly_income * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"نسبة الدين إلى الدخل","resultLabelEn":"Debt-to-income ratio","decimals":2,"showEquation":true}'::jsonb, '[{"key":"monthly_debt_payments","label":"الأقساط الشهرية","type":"number","required":true,"step":0.01,"min":0},{"key":"monthly_income","label":"الدخل الشهري","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"monthly_debt_payments","label":"Monthly debt payments","type":"number","required":true,"step":0.01,"min":0},{"key":"monthly_income","label":"Monthly income","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 3092, false),
  ('personal-finance-tools', 'simple-loan-interest-calculator', 'حاسبة الفائدة البسيطة للقرض', 'Simple Loan Interest Calculator', 'احسب الفائدة البسيطة للقرض.', 'Calculate simple loan interest.', '{"expression":"principal * annual_rate / 100 * years","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"إجمالي الفائدة","resultLabelEn":"Total interest","decimals":2,"showEquation":true}'::jsonb, '[{"key":"principal","label":"أصل القرض","type":"number","required":true,"step":0.01,"min":0},{"key":"annual_rate","label":"النسبة السنوية","type":"number","required":true,"step":0.01,"min":0},{"key":"years","label":"عدد السنوات","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"principal","label":"Loan principal","type":"number","required":true,"step":0.01,"min":0},{"key":"annual_rate","label":"Annual rate","type":"number","required":true,"step":0.01,"min":0},{"key":"years","label":"Years","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 3093, false),
  ('personal-finance-tools', 'monthly-savings-goal-calculator', 'حاسبة الادخار الشهري للهدف', 'Monthly Savings Goal Calculator', 'احسب المبلغ الشهري اللازم للوصول إلى هدف.', 'Calculate monthly savings required for a goal.', '{"expression":"(target_amount - current_savings) / months","outputUnitAr":" ر.س/شهر","outputUnitEn":" SAR/month","resultLabelAr":"الادخار الشهري المطلوب","resultLabelEn":"Required monthly savings","decimals":2,"showEquation":true}'::jsonb, '[{"key":"target_amount","label":"المبلغ المستهدف","type":"number","required":true,"step":0.01,"min":0},{"key":"current_savings","label":"المدخرات الحالية","type":"number","required":true,"step":0.01,"min":0},{"key":"months","label":"عدد الأشهر","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"target_amount","label":"Target amount","type":"number","required":true,"step":0.01,"min":0},{"key":"current_savings","label":"Current savings","type":"number","required":true,"step":0.01,"min":0},{"key":"months","label":"Months","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 3094, false),
  ('personal-finance-tools', 'monthly-budget-remainder-calculator', 'حاسبة المتبقي من الميزانية', 'Monthly Budget Remainder Calculator', 'احسب المتبقي بعد المصروفات والادخار.', 'Calculate remaining monthly budget.', '{"expression":"monthly_income - monthly_expenses - monthly_savings","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"المتبقي من الميزانية","resultLabelEn":"Budget remainder","decimals":2,"showEquation":true}'::jsonb, '[{"key":"monthly_income","label":"الدخل الشهري","type":"number","required":true,"step":0.01,"min":0},{"key":"monthly_expenses","label":"المصروفات الشهرية","type":"number","required":true,"step":0.01,"min":0},{"key":"monthly_savings","label":"الادخار الشهري","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"monthly_income","label":"Monthly income","type":"number","required":true,"step":0.01,"min":0},{"key":"monthly_expenses","label":"Monthly expenses","type":"number","required":true,"step":0.01,"min":0},{"key":"monthly_savings","label":"Monthly savings","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 3095, false),
  ('personal-finance-tools', 'expense-growth-rate-calculator', 'حاسبة نمو المصروفات', 'Expense Growth Rate Calculator', 'احسب تغير المصروفات بين فترتين.', 'Calculate expense growth between periods.', '{"expression":"(current_expenses - previous_expenses) / previous_expenses * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"نمو المصروفات","resultLabelEn":"Expense growth","decimals":2,"showEquation":true}'::jsonb, '[{"key":"current_expenses","label":"المصروفات الحالية","type":"number","required":true,"step":0.01,"min":0},{"key":"previous_expenses","label":"المصروفات السابقة","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"current_expenses","label":"Current expenses","type":"number","required":true,"step":0.01,"min":0},{"key":"previous_expenses","label":"Previous expenses","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 3096, false),
  ('personal-finance-tools', 'annual-subscription-cost-calculator', 'حاسبة تكلفة الاشتراكات السنوية', 'Annual Subscription Cost Calculator', 'احسب مجموع تكلفة الاشتراكات خلال سنة.', 'Calculate annual subscription cost.', '{"expression":"monthly_subscriptions * 12 + annual_subscriptions","outputUnitAr":" ر.س/سنة","outputUnitEn":" SAR/year","resultLabelAr":"تكلفة الاشتراكات السنوية","resultLabelEn":"Annual subscription cost","decimals":2,"showEquation":true}'::jsonb, '[{"key":"monthly_subscriptions","label":"الاشتراكات الشهرية","type":"number","required":true,"step":0.01,"min":0},{"key":"annual_subscriptions","label":"الاشتراكات السنوية","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"monthly_subscriptions","label":"Monthly subscriptions","type":"number","required":true,"step":0.01,"min":0},{"key":"annual_subscriptions","label":"Annual subscriptions","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 3097, false),
  ('personal-finance-tools', 'personal-cash-flow-calculator', 'حاسبة التدفق النقدي الشخصي', 'Personal Cash Flow Calculator', 'احسب صافي التدفق النقدي الشهري.', 'Calculate net monthly cash flow.', '{"expression":"monthly_income - monthly_expenses","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"صافي التدفق النقدي","resultLabelEn":"Net cash flow","decimals":2,"showEquation":true}'::jsonb, '[{"key":"monthly_income","label":"الدخل الشهري","type":"number","required":true,"step":0.01,"min":0},{"key":"monthly_expenses","label":"المصروفات الشهرية","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"monthly_income","label":"Monthly income","type":"number","required":true,"step":0.01,"min":0},{"key":"monthly_expenses","label":"Monthly expenses","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 3098, false),
  ('personal-finance-tools', 'net-worth-calculator', 'حاسبة صافي الثروة', 'Net Worth Calculator', 'احسب صافي الثروة من الأصول والالتزامات.', 'Calculate net worth from assets and liabilities.', '{"expression":"total_assets - total_liabilities","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"صافي الثروة","resultLabelEn":"Net worth","decimals":2,"showEquation":true}'::jsonb, '[{"key":"total_assets","label":"إجمالي الأصول","type":"number","required":true,"step":0.01,"min":0},{"key":"total_liabilities","label":"إجمالي الالتزامات","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"total_assets","label":"Total assets","type":"number","required":true,"step":0.01,"min":0},{"key":"total_liabilities","label":"Total liabilities","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 3099, false);

do $$
declare
  v_count integer;
  v_duplicates integer;
begin
  select count(*) into v_count from wave3_formula_tool_seed;
  if v_count <> 100 then
    raise exception 'WAVE3_TOOL_COUNT_MISMATCH:%', v_count;
  end if;

  select count(*) - count(distinct slug)
  into v_duplicates
  from wave3_formula_tool_seed;

  if v_duplicates <> 0 then
    raise exception 'WAVE3_DUPLICATE_SLUGS:%', v_duplicates;
  end if;
end;
$$;

insert into public.tools(
  slug, title_ar, title_en, short_description, category_id, engine_type,
  input_schema, output_schema, runtime_config, pricing_mode, fixed_points,
  minimum_points, requires_auth, is_featured, is_active, sort_order,
  seo_title, seo_description
)
select
  seed.slug,
  seed.title_ar,
  seed.title_en,
  seed.description_ar,
  category.id,
  'formula',
  jsonb_build_object('submitLabel', seed.submit_ar, 'fields', seed.input_fields),
  jsonb_build_object('type', 'number', 'format', 'runtime'),
  seed.runtime_config,
  'free',
  0,
  0,
  false,
  seed.is_featured,
  true,
  seed.sort_order,
  seed.title_ar || ' مجانًا | أمبراطورية الويب',
  seed.description_ar
from wave3_formula_tool_seed seed
join public.categories category on category.slug = seed.category_slug
on conflict (slug) do update set
  title_ar = excluded.title_ar,
  title_en = excluded.title_en,
  short_description = excluded.short_description,
  category_id = excluded.category_id,
  engine_type = excluded.engine_type,
  input_schema = excluded.input_schema,
  output_schema = excluded.output_schema,
  runtime_config = excluded.runtime_config,
  pricing_mode = excluded.pricing_mode,
  fixed_points = excluded.fixed_points,
  minimum_points = excluded.minimum_points,
  requires_auth = excluded.requires_auth,
  is_featured = excluded.is_featured,
  is_active = excluded.is_active,
  sort_order = excluded.sort_order,
  seo_title = excluded.seo_title,
  seo_description = excluded.seo_description,
  updated_at = now();

insert into public.tool_translations(
  tool_id, locale_id, title, short_description, seo_title, seo_description,
  prompt_template_override
)
select
  tool.id,
  locale.id,
  case when locale.code = 'ar' then seed.title_ar else seed.title_en end,
  case when locale.code = 'ar' then seed.description_ar else seed.description_en end,
  case
    when locale.code = 'ar' then seed.title_ar || ' مجانًا | أمبراطورية الويب'
    else seed.title_en || ' Free | Web Empire'
  end,
  case when locale.code = 'ar' then seed.description_ar else seed.description_en end,
  null
from wave3_formula_tool_seed seed
join public.tools tool on tool.slug = seed.slug
join public.locales locale on locale.code in ('ar', 'en')
on conflict (tool_id, locale_id) do update set
  title = excluded.title,
  short_description = excluded.short_description,
  seo_title = excluded.seo_title,
  seo_description = excluded.seo_description,
  prompt_template_override = null,
  updated_at = now();

insert into public.tool_field_translations(
  tool_id, locale_id, field_key, label, placeholder, help_text, options
)
select
  tool.id,
  locale.id,
  field.value ->> 'key',
  field.value ->> 'label',
  nullif(field.value ->> 'placeholder', ''),
  nullif(field.value ->> 'helpText', ''),
  field.value -> 'options'
from wave3_formula_tool_seed seed
join public.tools tool on tool.slug = seed.slug
join public.locales locale on locale.code in ('ar', 'en')
cross join lateral jsonb_array_elements(
  case when locale.code = 'ar' then seed.input_fields else seed.english_fields end
) field(value)
on conflict (tool_id, locale_id, field_key) do update set
  label = excluded.label,
  placeholder = excluded.placeholder,
  help_text = excluded.help_text,
  options = excluded.options,
  updated_at = now();

insert into public.tool_field_translations(
  tool_id, locale_id, field_key, label, placeholder, help_text, options
)
select
  tool.id,
  locale.id,
  '__submit__',
  case when locale.code = 'ar' then seed.submit_ar else seed.submit_en end,
  null, null, null
from wave3_formula_tool_seed seed
join public.tools tool on tool.slug = seed.slug
join public.locales locale on locale.code in ('ar', 'en')
on conflict (tool_id, locale_id, field_key) do update set
  label = excluded.label,
  updated_at = now();

do $$
declare
  r record;
begin
  for r in
    select
      category.slug,
      count(tool.id) filter (where tool.is_active) as active_tools
    from public.categories category
    left join public.tools tool on tool.category_id = category.id
    where category.slug in (
    'automotive-tools',
    'construction-tools',
    'agriculture-tools',
    'event-tools',
    'hr-tools',
    'seo-tools',
    'web-tools',
    'design-tools',
    'customer-service-tools',
    'personal-finance-tools'
    )
    group by category.slug
  loop
    if r.active_tools < 5 or r.active_tools > 50 then
      raise exception 'CATEGORY_TOOL_RANGE_VIOLATION:%:%', r.slug, r.active_tools;
    end if;
  end loop;
end;
$$;

commit;

